import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { useMusic } from '../../context/MusicContext';
import { Trophy, Heart, Headphones, Flame } from 'lucide-react';

const Ranking = () => {
  const [topSongs, setTopSongs] = useState([]);
  const [loading, setLoading] = useState(true);

  // Lấy dữ liệu từ Context để đồng bộ trạng thái "đã thích" của người dùng
  const { favorites = [], toggleLikeGlobal } = useMusic();
  const loggedInUser = JSON.parse(localStorage.getItem('user'));

  useEffect(() => {
    fetchRanking();
  }, []);

  const fetchRanking = async () => {
    try {
      const res = await axios.get('http://localhost:5000/api/songs/ranking');
      setTopSongs(res.data);
    } catch (err) {
      console.error("Lỗi tải bảng xếp hạng:", err);
    } finally {
      setLoading(false);
    }
  };

  /**
   * HÀM XỬ LÝ NHẢY SỐ LƯỢT LIKE NGAY LẬP TỨC
   */
  const handleLikeAction = async (songId) => {
    if (!loggedInUser) return alert("Vui lòng đăng nhập để bình chọn!");

    const userId = loggedInUser._id || loggedInUser.id;
    // Kiểm tra trạng thái hiện tại từ Context
    const isCurrentlyLiked = favorites.includes(songId);

    // 1. Gọi API xử lý ở Backend thông qua Context
    await toggleLikeGlobal(songId);

    // 2. Cập nhật "số lượng" hiển thị trong state cục bộ của trang Ranking
    setTopSongs((prevSongs) =>
      prevSongs.map((song) => {
        if (song._id === songId) {
          let updatedLikes = [...(song.likes || [])];

          if (isCurrentlyLiked) {
            // Nếu đã like -> giờ là bỏ like: lọc bỏ userId khỏi mảng likes
            updatedLikes = updatedLikes.filter((id) => id !== userId);
          } else {
            // Nếu chưa like -> giờ là like: thêm userId vào mảng likes
            updatedLikes.push(userId);
          }

          return { ...song, likes: updatedLikes };
        }
        return song;
      })
    );
  };

  if (loading) return <div style={loadingStyle}>Đang tải bảng xếp hạng...</div>;

  return (
    <div style={rankPage}>
      <header style={rankHeader}>
        <div style={trophyContainer}>
          <Trophy size={60} color="#FFD700" />
          <Flame size={40} color="#ff4d4d" style={flameIcon} />
        </div>
        <h1 style={titleStyle}>BẢNG XẾP HẠNG IAMNHAC</h1>
        <p style={subtitleStyle}>Top 10 bài hát có sức ảnh hưởng nhất tuần này</p>
      </header>

      <div style={rankList}>
        {topSongs.map((song, index) => {
          const isLiked = favorites?.includes(song._id);

          return (
            <div key={song._id} style={rankItem(index)}>
              {/* Thứ hạng */}
              <div style={rankNumber(index)}>{index + 1}</div>

              {/* Ảnh bài hát */}
              <img 
                src={`http://localhost:5000${song.imageUrl}`} 
                style={rankImg} 
                alt={song.title} 
              />

              {/* Thông tin bài hát */}
              <div style={{ flex: 1 }}>
                <div style={songName}>{song.title}</div>
                <div style={songArt}>{song.artist}</div>
              </div>

              {/* Chỉ số thống kê */}
              <div style={statsContainer}>
                {/* Lượt nghe */}
                <div style={statItem}>
                  <Headphones size={16} color="#1db954" />
                  <span style={statValue}>{song.playCount || 0}</span>
                </div>

                {/* Lượt thích - Khu vực nhảy số */}
                <div 
                  style={{ ...statItem, cursor: 'pointer', minWidth: '60px' }} 
                  onClick={() => handleLikeAction(song._id)}
                >
                  <Heart 
                    size={20} 
                    fill={isLiked ? "#ff4d4d" : "none"} 
                    color={isLiked ? "#ff4d4d" : "#b3b3b3"} 
                    style={{ transition: 'transform 0.2s' }}
                  />
                  <span style={{ 
                    color: isLiked ? "#ff4d4d" : "#fff", 
                    fontWeight: 'bold',
                    fontSize: '16px' 
                  }}>
                    {song.likes?.length || 0}
                  </span>
                </div>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

/* --- PHẦN STYLES TỐI ƯU --- */
const rankPage = { padding: '40px 20px', maxWidth: '1000px', margin: '0 auto', color: '#fff', paddingBottom: '120px' };
const rankHeader = { textAlign: 'center', marginBottom: '50px' };
const trophyContainer = { position: 'relative', display: 'inline-block' };
const flameIcon = { position: 'absolute', bottom: -5, right: -10 };
const titleStyle = { fontSize: '36px', fontWeight: '900', margin: '15px 0 5px 0', letterSpacing: '1px', color: '#1db954' };
const subtitleStyle = { color: '#b3b3b3', fontSize: '16px' };

const rankList = { background: '#181818', borderRadius: '15px', overflow: 'hidden', boxShadow: '0 10px 30px rgba(0,0,0,0.3)' };
const rankItem = (i) => ({
  display: 'flex', alignItems: 'center', padding: '18px 25px', borderBottom: '1px solid #282828',
  background: i === 0 ? 'linear-gradient(90deg, rgba(29,185,84,0.1) 0%, transparent 100%)' : 'transparent',
  transition: 'background 0.2s',
  ':hover': { background: '#282828' }
});

const rankNumber = (i) => ({
  fontSize: '22px', fontWeight: '900', width: '45px',
  color: i === 0 ? '#FFD700' : i === 1 ? '#C0C0C0' : i === 2 ? '#CD7F32' : '#444'
});

const rankImg = { width: '55px', height: '55px', borderRadius: '6px', marginRight: '20px', objectFit: 'cover', boxShadow: '0 4px 10px rgba(0,0,0,0.3)' };
const songName = { fontSize: '17px', fontWeight: 'bold', marginBottom: '4px' };
const songArt = { fontSize: '14px', color: '#b3b3b3' };

const statsContainer = { display: 'flex', gap: '30px', alignItems: 'center' };
const statItem = { display: 'flex', alignItems: 'center', gap: '10px' };
const statValue = { fontSize: '15px', fontWeight: '500' };
const loadingStyle = { color: '#fff', textAlign: 'center', marginTop: '100px', fontSize: '18px' };

export default Ranking;
